usort(
      $array,
      function ($a, $b) use ($is_files) {
        if ($is_files)
          return strcmp($a->getFileName(), $b->getFileName());
        else {
          return strcmp($a->getName(), $b->getName());
        }
      }
    )

array_filter($replaceBlocks, function ($replaceBlock)
		{
			 $fonts = ['.ttf', '.woff', '.woff2', '.otf']; 
			 foreach($fonts as $extcheck)
			 {
				  if (strpos($replaceBlock->url, $extcheck) !== false)
				  {	
						return false; 
				  }
			 }
			 return true; 

		})

array_filter($replaceBlocks, function ($replaceBlock) use ($allMatches) {
							if (in_array($replaceBlock->raw_url, $allMatches))
							{
								return false;
							}
							return true;
			 })

array_filter($replaceBlocks, function ($replaceBlock)
     {
          // Check if block if from different domain (skip) but only if host set ( not relative )
          if (strpos($replaceBlock->url, $this->site_domain) === false && isset($replaceBlock->parsed['host']))
          {
             return false;
          }
          return true;
     })

array_filter($replaceBlocks, function ($replaceBlock)
      {
          if (strlen(trim($replaceBlock->url)) == 0)
          {
             return false;
          }

          $parsed = $replaceBlock->parsed; 
          // Most likely a non-url.
          if (! isset($parsed['path']) && ! isset($parsed['host']))
          {
             return false; 
          }

          return true;
      })

